const d = new Date();
d.setDate(d.getDate() - 1);
return [{json: {yesterday: d.toISOString().split('T')[0]}}];

// ===== TOGGLE METRICS HERE =====
const SHOW_SPEND       = true;
const SHOW_CLICKS      = true;
const SHOW_IMPRESSIONS = true;
const SHOW_CONVERSIONS = true;
const SHOW_CPA         = true;
const SHOW_INSTALLS    = true;
const SHOW_ROAS        = true;
const SHOW_DISCREPANCY = true;
const SHOW_ARPU        = true;
const SHOW_CTR         = true;
const SHOW_CONV_RATE   = true;
const SIG_THRESHOLD    = 0.10; // flag differences >= 10%
// ================================

const date = $('Set Yesterday').first().json.yesterday;

// --- Google Ads ---
const adsRaw = $('Google Ads').first().json;
const results = adsRaw.results || [];
let spend = 0, clicks = 0, impressions = 0, conversions = 0;
for (const r of results) {
  spend       += (r.metrics?.costMicros || 0) / 1e6;
  clicks      += parseInt(r.metrics?.clicks || 0);
  impressions += parseInt(r.metrics?.impressions || 0);
  conversions += parseFloat(r.metrics?.conversions || 0);
}
const cpa = conversions > 0 ? spend / conversions : null;

// --- AppsFlyer CSV parser ---
const parseAF = (raw) => {
  const csv = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const lines = csv.trim().split('\n').filter(l => l.trim());
  if (lines.length < 2) return {total: 0, byCampaign: {}};
  const headers = lines[0].split(',').map(h => h.trim().replace(/"/g, ''));
  const campIdx     = headers.indexOf('Campaign (c)') !== -1 ? headers.indexOf('Campaign (c)') : headers.indexOf('Campaign');
  const installsIdx = headers.indexOf('Installs');
  const clicksIdx   = headers.indexOf('Clicks');
  const impIdx      = headers.indexOf('Impressions');
  const costIdx     = headers.indexOf('Total Cost') !== -1 ? headers.indexOf('Total Cost') : headers.indexOf('Cost');
  const revIdx      = headers.indexOf('Total Revenue');
  const ecpiIdx     = headers.indexOf('Average eCPI');
  const roiIdx      = headers.indexOf('ROI');
  const byCampaign = {};
  let total = 0;
  for (const line of lines.slice(1)) {
    const vals = line.split(',').map(v => v.trim().replace(/"/g, ''));
    const camp = vals[campIdx] || 'Unknown';
    if (!byCampaign[camp]) byCampaign[camp] = {installs:0, clicks:0, impressions:0, cost:0, revenue:0, ecpi:0, roi:'N/A'};
    byCampaign[camp].installs    += parseInt(vals[installsIdx]   || 0);
    byCampaign[camp].clicks      += parseInt(vals[clicksIdx]     || 0);
    byCampaign[camp].impressions += parseInt(vals[impIdx]        || 0);
    byCampaign[camp].cost        += parseFloat(vals[costIdx]     || 0);
    byCampaign[camp].revenue     += parseFloat(vals[revIdx]      || 0);
    byCampaign[camp].ecpi         = parseFloat(vals[ecpiIdx]     || 0);
    byCampaign[camp].roi          = vals[roiIdx] || 'N/A';
    total += parseInt(vals[installsIdx] || 0);
  }
  return {total, byCampaign};
};

const getAF = (name) => { const r = $(name).first().json; return r.data || r.body || (typeof r === 'string' ? r : JSON.stringify(r)); };
const android = parseAF(getAF('AppsFlyer Android'));
const ios     = parseAF(getAF('AppsFlyer iOS'));

const afByCampaign = {};
const mergeInto = (src) => {
  for (const [k, v] of Object.entries(src)) {
    if (!afByCampaign[k]) afByCampaign[k] = {installs:0, clicks:0, impressions:0, cost:0, revenue:0, ecpi:0, roi:'N/A'};
    afByCampaign[k].installs    += v.installs    || 0;
    afByCampaign[k].clicks      += v.clicks      || 0;
    afByCampaign[k].impressions += v.impressions || 0;
    afByCampaign[k].cost        += v.cost        || 0;
    afByCampaign[k].revenue     += v.revenue     || 0;
    afByCampaign[k].ecpi         = v.ecpi        || afByCampaign[k].ecpi;
    afByCampaign[k].roi          = v.roi         || afByCampaign[k].roi;
  }
};
mergeInto(android.byCampaign);
mergeInto(ios.byCampaign);

const totalInstalls = android.total + ios.total;
const cpi = totalInstalls > 0 ? (spend / totalInstalls).toFixed(2) : 'N/A';

// --- Helpers ---
const isSig = (a, b) => {
  if (a == null || b == null || a === 0 || b === 0) return false;
  return Math.abs(a - b) / Math.max(Math.abs(a), Math.abs(b)) >= SIG_THRESHOLD;
};
const diffPct = (af, ga) => {
  if (ga === 0) return af === 0 ? '0.0%' : '+INF%';
  const d = ((af - ga) / Math.abs(ga)) * 100;
  return (d >= 0 ? '+' : '') + d.toFixed(1) + '%';
};
const p = (s, n) => String(s).padEnd(n);

// row: compared metric (both AF and GA)
const row = (label, afVal, gaVal, afNum, gaNum, prefix) => {
  const flag = isSig(afNum, gaNum) ? ' ⚠' : '';
  const diff = (afNum != null && gaNum != null && !(afNum === 0 && gaNum === 0))
    ? diffPct(afNum, gaNum) : '—';
  const afStr = prefix ? prefix + afVal : String(afVal);
  const gaStr = prefix ? prefix + gaVal : String(gaVal);
  return p(label, 16) + p(afStr, 14) + p(gaStr, 14) + p(diff + flag, 12);
};

// rowAF: AF-only metric
const rowAF = (label, afVal) => p(label, 16) + p(afVal, 14) + p('—', 14) + '—';

// --- Build Slack message ---
const out = [`📊 *Daily Report — ${date}*`, ''];

out.push('*Overall — Google Ads (Urban Heat)*');
const totalCtr      = impressions > 0 ? ((clicks / impressions) * 100).toFixed(2) + '%' : 'N/A';
const totalConvRate = clicks > 0 ? ((conversions / clicks) * 100).toFixed(2) + '%' : 'N/A';
if (SHOW_SPEND)       out.push(`• Spend: $${spend.toFixed(2)}`);
if (SHOW_CLICKS)      out.push(`• Clicks: ${clicks.toLocaleString()}`);
if (SHOW_IMPRESSIONS) out.push(`• Impressions: ${impressions.toLocaleString()}`);
if (SHOW_CONVERSIONS) out.push(`• Conversions: ${conversions.toFixed(0)}`);
if (SHOW_CPA && cpa)  out.push(`• CPA: $${cpa.toFixed(2)}`);
if (SHOW_CTR)         out.push(`• CTR: ${totalCtr}`);
if (SHOW_CONV_RATE)   out.push(`• Conv Rate: ${totalConvRate}`);

out.push('');
out.push('*Per Campaign:*');

for (const r of results) {
  const name  = r.campaign?.name || 'Unknown';
  const gaS   = (r.metrics?.costMicros || 0) / 1e6;
  const gaCl  = parseInt(r.metrics?.clicks || 0);
  const gaImp = parseInt(r.metrics?.impressions || 0);
  const gaCv  = parseFloat(r.metrics?.conversions || 0);
  const gaCpa = gaCv > 0 ? gaS / gaCv : null;
  const gaCtr = gaImp > 0 ? (gaCl / gaImp) * 100 : null;
  const gaConvRate = gaCl > 0 ? (gaCv / gaCl) * 100 : null;

  const af = afByCampaign[name] || {installs:0, clicks:0, impressions:0, cost:0, revenue:0, ecpi:0, roi:'N/A'};
  const afCost     = af.cost || 0;
  const afRev      = af.revenue || 0;
  const afEcpi     = af.ecpi || 0;
  const afRoas     = afCost > 0 ? (afRev / afCost) * 100 : null;
  const afRoiNum   = af.roi && af.roi !== 'N/A' ? parseFloat(af.roi) : null;
  const afArpu     = af.installs > 0 ? afRev / af.installs : null;
  const afCtr      = af.impressions > 0 ? (af.clicks / af.impressions) * 100 : null;
  const afConvRate = af.clicks > 0 ? (af.installs / af.clicks) * 100 : null;

  out.push('');
  out.push(`  › *${name}*`);
  out.push('```');
  out.push(p('Category', 16) + p('AppsFlyer', 14) + p('Google Ads', 14) + 'Diff');
  out.push('─'.repeat(56));
  if (SHOW_SPEND)       out.push(row('Spend',        afCost.toFixed(2),   gaS.toFixed(2),   afCost,           gaS,   '$'));
  if (SHOW_CLICKS)      out.push(row('Clicks',        (af.clicks||0).toLocaleString(), gaCl.toLocaleString(), af.clicks||0, gaCl));
  if (SHOW_IMPRESSIONS) out.push(row('Impressions',   (af.impressions||0).toLocaleString(), gaImp.toLocaleString(), af.impressions||0, gaImp));
  if (SHOW_CONVERSIONS) out.push(row('Conv/Install',  String(af.installs||0), gaCv.toFixed(0), af.installs||0, gaCv));
  if (SHOW_CPA)         out.push(row('CPA / eCPI',    afEcpi > 0 ? afEcpi.toFixed(2) : '—', gaCpa != null ? gaCpa.toFixed(2) : '—', afEcpi > 0 ? afEcpi : null, gaCpa, '$'));
  if (SHOW_CTR)         out.push(row('CTR',           afCtr != null ? afCtr.toFixed(2)+'%' : '—', gaCtr != null ? gaCtr.toFixed(2)+'%' : '—', afCtr, gaCtr));
  if (SHOW_CONV_RATE)   out.push(row('Conv Rate',     afConvRate != null ? afConvRate.toFixed(2)+'%' : '—', gaConvRate != null ? gaConvRate.toFixed(2)+'%' : '—', afConvRate, gaConvRate));
  out.push('─'.repeat(56));
  if (SHOW_ROAS) out.push(rowAF('ROAS',    afRoas    != null ? afRoas.toFixed(0)+'%'    : '—'));
  out.push(       rowAF('ROI',     afRoiNum  != null ? afRoiNum.toFixed(2)+'%'  : '—'));
  out.push(       rowAF('Revenue', '$'+afRev.toFixed(2)));
  if (SHOW_ARPU) out.push(rowAF('ARPU',    afArpu    != null ? '$'+afArpu.toFixed(4)    : '—'));
  out.push('```');
}

out.push('');
out.push('*AppsFlyer Totals (Google Ads traffic only)*');
if (SHOW_INSTALLS) out.push(`• Total Installs: ${totalInstalls.toLocaleString()}  (🤖 ${android.total} Android  /  🍎 ${ios.total} iOS)`);
if (SHOW_DISCREPANCY) {
  out.push('');
  const convGap = conversions - totalInstalls;
  const gapDir = convGap > 0 ? '⬆ GA higher' : '⬇ AF higher';
  out.push(`*Conversion Gap:* ${Math.abs(convGap).toFixed(0)} installs (${gapDir})`);
  out.push(`*CPI:* $${cpi} (Ads spend / AF installs)`);
}
out.push('');
out.push('_⚠ = difference ≥10%_');

return [{json: {message: out.join('\n')}}];

const message = $('Build Report').first().json.message;
return [{
  json: {
    model: 'gpt-4.1-mini',
    max_tokens: 300,
    messages: [
      {
        role: 'system',
        content: 'You are a mobile gaming performance marketing analyst. You receive a daily Google Ads vs AppsFlyer report and write a short Slack-ready summary for the team. Be direct and concise - 4 to 6 bullet points max. Flag anything unusual: big spend days, high discrepancies between GA and AF, poor CPI, strong ROAS, or campaigns that stand out. Write in plain language.'
      },
      {
        role: 'user',
        content: 'Here is today performance report. Summarize the most important takeaways:\n\n' + message
      }
    ]
  }
}];

const summary = $('AI Summary').first().json.choices?.[0]?.message?.content?.trim() || '';
const report  = $('Build Report').first().json.message;
const fullMessage = summary
  ? '*AI Summary*\n' + summary + '\n\n' + '-'.repeat(30) + '\n\n' + report
  : report;
return [{json: {message: fullMessage}}];
